const rawOutput = $input.first().json.output
const contas = $('Aggregate6').first().json.data

// ===========================
// 1 - Extrair JSON do texto
// ===========================

const match = rawOutput.match(/\{[\s\S]*?\}/);

if (!match) {
  return [{ json: { numero_conta: false } }];
}

let parsed;

try {
  parsed = JSON.parse(match[0]);
} catch {
  return [{ json: { numero_conta: false } }];
}

// ===========================
// 2 - Verificar ID retornado
// ===========================

const idConta = parsed.id_conta;

if (!idConta || idConta === "false") {
  return [{ json: { numero_conta: false } }];
}

// ===========================
// 3 - Buscar no array
// ===========================

const contaEncontrada = contas.find(c => Number(c.ID) === Number(idConta));

if (!contaEncontrada) {
  return [{ json: { numero_conta: false } }];
}

// ===========================
// 4 - Retornar número da conta
// ===========================

return [
  {
    json: {
      numero_conta: contaEncontrada["Numero Conta"]
    }
  }
];

